local function check_permissions()
    local uri = ngx.var.uri
    local token = ngx.var.http_authorization
    
    -- Skip permission checks for admin and api endpoints
    if string.find(uri, "/admin") or string.find(uri, "/api") then
        return true
    end
    
    -- Validate token
    if not token or string.sub(token, 1, 7) ~= "Bearer " then
        ngx.status = 401
        ngx.say('Unauthorized')
        ngx.exit(401)
        return false
    end
    
    -- Extract token (assuming it's a simple string for this example)
    local jwt_token = string.sub(token, 8)
    
    -- Validate token (simplified - in reality you'd decode and verify JWT)
    if jwt_token == "" then
        ngx.status = 401
        ngx.say('Invalid token')
        ngx.exit(401)
        return false
    end
    
    -- Simulate token decoding to get user role
    -- In real implementation, you'd decode the JWT and extract claims
    local user_role = "user"  -- This would come from decoded token
    
    -- Check role permissions (example)
    if user_role == "admin" then
        return true
    elseif user_role == "user" and string.find(uri, "/user") then
        return true
    else
        ngx.status = 403
        ngx.say('Forbidden')
        ngx.exit(403)
        return false
    end
end

